-- 0025_bias_taxonomy.sql
-- Cognitive-bias taxonomy: 78 literature-grounded entries.
-- Extends the 20 seed biases; feeds cognitive-bias-simulator + suggested_biases
-- + scenario_bias_applications. Idempotent and safe to re-run.

ON CONFLICT (slug) DO UPDATE SET
  name        = EXCLUDED.name,
  description  = EXCLUDED.description,
  source       = EXCLUDED.source,
  examples     = EXCLUDED.examples,
  mitigations  = EXCLUDED.mitigations;
