INSERT INTO biases (slug, name, description, examples, mitigations, source) VALUES
('anchoring','Anchoring','Over-relying on the first piece of information encountered when making decisions.','["Fixating on an initial asking price during a negotiation","Estimating a value near a recently seen but irrelevant number"]'::jsonb,'["Consider multiple reference points","Generate an independent estimate before seeing any anchor"]'::jsonb,'Tversky & Kahneman (1974)'),
('availability','Availability Heuristic','Judging likelihood by how easily examples come to mind rather than by base rates.','["Overestimating plane-crash risk after seeing news coverage"]'::jsonb,'["Consult actual frequency data","Ask what is memorable vs. what is common"]'::jsonb,'Tversky & Kahneman (1973)'),
('confirmation','Confirmation Bias','Seeking and weighting evidence that confirms existing beliefs.','["Reading only sources that agree with a thesis"]'::jsonb,'["Actively seek disconfirming evidence","Argue the opposing case"]'::jsonb,'Wason (1960)'),
('loss-aversion','Loss Aversion','Losses feel roughly twice as painful as equivalent gains feel good.','["Holding a losing position to avoid realizing the loss"]'::jsonb,'["Frame decisions in terms of final wealth","Pre-commit to exit rules"]'::jsonb,'Kahneman & Tversky (1979)'),
('sunk-cost','Sunk-Cost Fallacy','Continuing an endeavor because of already-invested resources.','["Pouring more money into a failing project to justify past spend"]'::jsonb,'["Evaluate only marginal future costs and benefits","Ignore unrecoverable past costs"]'::jsonb,'Arkes & Blumer (1985)'),
('overconfidence','Overconfidence','Overestimating the accuracy of one’s knowledge or predictions.','["Setting 90% confidence intervals that are hit far less often"]'::jsonb,'["Track calibration over time","Widen uncertainty ranges"]'::jsonb,'Fischhoff et al. (1977)'),
('dunning-kruger','Dunning–Kruger Effect','Low-skill individuals overestimate competence; experts underestimate it.','["A novice rating their expertise above a specialist"]'::jsonb,'["Seek external assessment","Compare against objective benchmarks"]'::jsonb,'Kruger & Dunning (1999)'),
('hindsight','Hindsight Bias','Seeing past events as having been predictable after they occur.','["“I knew it all along” after a market crash"]'::jsonb,'["Record predictions in advance","Review the information available at the time"]'::jsonb,'Fischhoff (1975)'),
('framing','Framing Effect','Drawing different conclusions from the same information based on presentation.','["Preferring “90% survival” over “10% mortality”"]'::jsonb,'["Reframe the choice in the opposite valence","Standardize the presentation"]'::jsonb,'Tversky & Kahneman (1981)'),
('recency','Recency Bias','Weighting recent events more heavily than earlier ones.','["Extrapolating the last few days of returns indefinitely"]'::jsonb,'["Zoom out to longer history","Weight by relevance, not recency"]'::jsonb,'Behavioral finance literature'),
('herd-behavior','Herd Behavior','Following the actions of a larger group rather than independent judgment.','["Buying an asset only because everyone else is"]'::jsonb,'["Form an independent thesis first","Ask what the crowd might be missing"]'::jsonb,'Banerjee (1992)'),
('fomo','Fear of Missing Out','Anxiety that others are benefiting, driving impulsive participation.','["Chasing a parabolic move late"]'::jsonb,'["Pre-define entry criteria","Accept that missing some opportunities is normal"]'::jsonb,'Social psychology literature'),
('gamblers-fallacy','Gambler’s Fallacy','Believing past independent outcomes affect future probabilities.','["Expecting red after a run of black on roulette"]'::jsonb,'["Treat independent events as independent","Check whether outcomes are truly memoryless"]'::jsonb,'Laplace (1796)'),
('hot-hand','Hot-Hand Fallacy','Believing a streak of successes will continue due to being “on fire.”','["Doubling size after a few winning trades"]'::jsonb,'["Test for genuine autocorrelation","Separate skill from variance"]'::jsonb,'Gilovich et al. (1985)'),
('disposition-effect','Disposition Effect','Selling winners too early and holding losers too long.','["Locking in small gains while letting losses run"]'::jsonb,'["Use symmetric exit rules","Judge positions on forward prospects"]'::jsonb,'Shefrin & Statman (1985)'),
('endowment','Endowment Effect','Valuing something more simply because one owns it.','["Demanding far more to sell an item than one would pay for it"]'::jsonb,'["Ask the market-clearing price","Imagine not currently owning it"]'::jsonb,'Thaler (1980)'),
('status-quo','Status-Quo Bias','Preferring things to stay the same by doing nothing.','["Keeping a default allocation despite better options"]'::jsonb,'["Treat inaction as an active choice","Re-derive the optimal from scratch"]'::jsonb,'Samuelson & Zeckhauser (1988)'),
('ostrich-effect','Ostrich Effect','Avoiding negative information by refusing to look.','["Not checking a portfolio during a drawdown"]'::jsonb,'["Schedule regular reviews regardless of mood","Automate reporting"]'::jsonb,'Karlsson et al. (2009)'),
('self-serving','Self-Serving Bias','Attributing successes to self and failures to external factors.','["Crediting skill for gains, blaming the market for losses"]'::jsonb,'["Keep a decision journal","Apply the same standard to wins and losses"]'::jsonb,'Miller & Ross (1975)'),
('fundamental-attribution','Fundamental Attribution Error','Over-attributing others’ behavior to character over situation.','["Assuming a late colleague is lazy rather than delayed"]'::jsonb,'["Consider situational constraints","Ask what you would do in their context"]'::jsonb,'Ross (1977)'),
('halo-effect','Halo Effect','Letting one positive trait color overall judgment.','["Assuming an attractive founder is also competent"]'::jsonb,'["Rate attributes independently","Use structured criteria"]'::jsonb,'Thorndike (1920)'),
('negativity','Negativity Bias','Giving more weight to negative than positive information.','["One bad review outweighing many good ones"]'::jsonb,'["Weight evidence by base rate","Quantify the balance explicitly"]'::jsonb,'Rozin & Royzman (2001)'),
('optimism','Optimism Bias','Overestimating the likelihood of positive outcomes for oneself.','["Believing your project will beat the average failure rate"]'::jsonb,'["Use reference-class forecasting","Pre-mortem the plan"]'::jsonb,'Weinstein (1980)'),
('planning-fallacy','Planning Fallacy','Underestimating time, costs, and risks of future actions.','["A project that always overruns its own estimate"]'::jsonb,'["Base estimates on similar past projects","Add explicit buffers"]'::jsonb,'Kahneman & Tversky (1979)'),
('base-rate-neglect','Base-Rate Neglect','Ignoring general prevalence in favor of specific information.','["Overweighting a test result while ignoring disease rarity"]'::jsonb,'["Start from the base rate","Apply Bayes’ rule explicitly"]'::jsonb,'Kahneman & Tversky (1973)'),
('conjunction-fallacy','Conjunction Fallacy','Judging a specific combination as more likely than one of its parts.','["Rating “bank teller and activist” above “bank teller”"]'::jsonb,'["Remember P(A∧B) ≤ P(A)","Decompose the claim"]'::jsonb,'Tversky & Kahneman (1983)'),
('representativeness','Representativeness','Judging probability by similarity to a stereotype.','["Assuming a quiet person is a librarian not a salesperson"]'::jsonb,'["Anchor on base rates","Discount stereotype-fit"]'::jsonb,'Kahneman & Tversky (1972)'),
('survivorship','Survivorship Bias','Focusing on survivors and ignoring what failed.','["Studying only successful startups for lessons"]'::jsonb,'["Deliberately study failures","Reconstruct the full original set"]'::jsonb,'Wald (1943)'),
('clustering-illusion','Clustering Illusion','Seeing patterns in what are actually random sequences.','["Reading meaning into a random price wiggle"]'::jsonb,'["Test against a random benchmark","Compute the expected clustering"]'::jsonb,'Gilovich (1991)'),
('authority-bias','Authority Bias','Over-trusting the opinion of an authority figure.','["Following a pundit’s call without checking"]'::jsonb,'["Evaluate the argument, not the title","Seek independent corroboration"]'::jsonb,'Milgram (1963)'),
('bandwagon','Bandwagon Effect','Adopting beliefs because many others hold them.','["Buying a trend because it is popular"]'::jsonb,'["Assess the claim on its merits","Ask who benefits from the consensus"]'::jsonb,'Social psychology literature'),
('in-group','In-Group Bias','Favoring members of one’s own group.','["Trusting advice from your circle over better outside data"]'::jsonb,'["Blind the source when evaluating","Seek out-group perspectives"]'::jsonb,'Tajfel (1970)'),
('illusion-of-control','Illusion of Control','Overestimating one’s influence over outcomes.','["Believing a ritual affects a random result"]'::jsonb,'["Distinguish skill from luck","Track outcomes vs. actions"]'::jsonb,'Langer (1975)'),
('just-world','Just-World Hypothesis','Believing the world is fair, so people get what they deserve.','["Assuming victims must have caused their misfortune"]'::jsonb,'["Separate outcome from desert","Consider luck and structure"]'::jsonb,'Lerner (1980)'),
('action-bias','Action Bias','Preferring action over inaction even when waiting is better.','["Overtrading in a flat market"]'::jsonb,'["Set a bar for acting","Value the option of doing nothing"]'::jsonb,'Patt & Zeckhauser (2000)'),
('ambiguity-aversion','Ambiguity Aversion','Preferring known risks over unknown ones.','["Avoiding an unfamiliar market despite better odds"]'::jsonb,'["Quantify the ambiguity","Separate unknown from unfavorable"]'::jsonb,'Ellsberg (1961)'),
('zero-risk','Zero-Risk Bias','Preferring to eliminate one risk entirely over reducing several.','["Spending heavily to remove a tiny risk"]'::jsonb,'["Compare marginal risk reduction per dollar","Optimize total risk"]'::jsonb,'Baron et al. (1993)'),
('mental-accounting','Mental Accounting','Treating money differently based on arbitrary categories.','["Splurging “winnings” while guarding “salary”"]'::jsonb,'["Treat money as fungible","Optimize the whole balance sheet"]'::jsonb,'Thaler (1985)'),
('hyperbolic-discounting','Hyperbolic Discounting','Preferring smaller-sooner rewards over larger-later ones.','["Taking a small payout now over a larger one later"]'::jsonb,'["Pre-commit to the long-term choice","Use binding commitment devices"]'::jsonb,'Ainslie (1975)'),
('present-bias','Present Bias','Overweighting immediate payoffs relative to the future.','["Procrastinating despite future cost"]'::jsonb,'["Make future costs vivid","Automate long-term actions"]'::jsonb,'O’Donoghue & Rabin (1999)'),
('decoy-effect','Decoy Effect','A third inferior option shifts preference between two others.','["A pricey “decoy” nudging buyers to the middle tier"]'::jsonb,'["Evaluate options on absolute value","Remove irrelevant alternatives"]'::jsonb,'Huber et al. (1982)'),
('contrast-effect','Contrast Effect','Perception shifted by comparison with recent stimuli.','["A fair price seeming cheap after an expensive one"]'::jsonb,'["Judge against an absolute standard","Reset the reference point"]'::jsonb,'Behavioral literature'),
('peak-end','Peak–End Rule','Judging an experience by its peak and its end, not the average.','["Rating a trip by its best moment and finish"]'::jsonb,'["Sample the whole experience","Weight by duration"]'::jsonb,'Kahneman et al. (1993)'),
('escalation-of-commitment','Escalation of Commitment','Increasing investment in a failing course to justify prior choices.','["Adding to a losing bet to avoid admitting error"]'::jsonb,'["Set stop-loss rules in advance","Bring in an outside reviewer"]'::jsonb,'Staw (1976)'),
('reactance','Reactance','Doing the opposite of what is urged to preserve autonomy.','["Rejecting good advice because it was pushed"]'::jsonb,'["Separate the message from the messenger","Reframe as your own choice"]'::jsonb,'Brehm (1966)'),
('backfire-effect','Backfire Effect','Strengthening a belief when confronted with contradicting evidence.','["Doubling down after being corrected"]'::jsonb,'["Approach evidence with curiosity","Lower the stakes of being wrong"]'::jsonb,'Nyhan & Reifler (2010)'),
('belief-perseverance','Belief Perseverance','Maintaining beliefs after their basis is discredited.','["Holding a thesis after its premise is refuted"]'::jsonb,'["Re-derive conclusions from current evidence","Note when a premise falls"]'::jsonb,'Ross et al. (1975)'),
('illusory-superiority','Illusory Superiority','Overestimating one’s qualities relative to others.','["Most drivers rating themselves above average"]'::jsonb,'["Benchmark against real distributions","Seek candid feedback"]'::jsonb,'Social psychology literature'),
('spotlight-effect','Spotlight Effect','Overestimating how much others notice you.','["Assuming everyone saw a small mistake"]'::jsonb,'["Recognize others’ self-focus","Ask for calibration"]'::jsonb,'Gilovich et al. (2000)'),
('curse-of-knowledge','Curse of Knowledge','Assuming others share your background knowledge.','["An expert explaining over a novice’s head"]'::jsonb,'["Test explanations on a naive audience","Define terms explicitly"]'::jsonb,'Camerer et al. (1989)'),
('pseudocertainty','Pseudocertainty Effect','Treating a probable outcome as certain in multi-stage decisions.','["Ignoring an early-stage risk because a later stage feels safe"]'::jsonb,'["Multiply stage probabilities","Model the full tree"]'::jsonb,'Tversky & Kahneman (1981)'),
('denomination-effect','Denomination Effect','Spending small denominations more readily than large ones.','["Breaking a large bill makes it easier to spend"]'::jsonb,'["Track total outflow","Pre-budget regardless of denomination"]'::jsonb,'Raghubir & Srivastava (2009)'),
('money-illusion','Money Illusion','Thinking in nominal rather than real (inflation-adjusted) terms.','["Feeling richer from a raise below inflation"]'::jsonb,'["Adjust for inflation","Compare purchasing power"]'::jsonb,'Fisher (1928)'),
('focusing-illusion','Focusing Illusion','Overweighting one salient factor in a life judgment.','["Assuming a purchase will change happiness more than it does"]'::jsonb,'["Consider the full picture","Ask about day-to-day reality"]'::jsonb,'Schkade & Kahneman (1998)'),
('impact-bias','Impact Bias','Overestimating the intensity and duration of future feelings.','["Expecting a setback to feel worse for longer than it does"]'::jsonb,'["Recall past adaptation","Forecast with a discount"]'::jsonb,'Wilson & Gilbert (2003)'),
('omission','Omission Bias','Judging harmful actions as worse than equally harmful inactions.','["Preferring to do nothing even when acting saves more"]'::jsonb,'["Weigh outcomes, not act vs. omit","Make the cost of inaction explicit"]'::jsonb,'Spranca et al. (1991)'),
('pro-innovation','Pro-Innovation Bias','Overvaluing a new idea while ignoring its limitations.','["Adopting a novel tool because it is new"]'::jsonb,'["Demand evidence of net benefit","Pilot before committing"]'::jsonb,'Rogers (1962)'),
('semmelweis-reflex','Semmelweis Reflex','Reflexively rejecting new evidence that contradicts norms.','["Dismissing a finding that breaks convention"]'::jsonb,'["Judge evidence on quality","Separate novelty from validity"]'::jsonb,'History of science'),
('restraint-bias','Restraint Bias','Overestimating one’s ability to control impulses.','["Keeping temptation nearby, sure of resisting"]'::jsonb,'["Reduce exposure to triggers","Use precommitment"]'::jsonb,'Nordgren et al. (2009)'),
('empathy-gap','Empathy Gap','Underestimating how visceral states change decisions.','["Overcommitting when calm, then buckling under stress"]'::jsonb,'["Plan for the heated state","Build in cool-off periods"]'::jsonb,'Loewenstein (1996)'),
('projection-bias','Projection Bias','Assuming future preferences match current ones.','["Grocery shopping while hungry"]'::jsonb,'["Decide in a neutral state","Discount current cravings"]'::jsonb,'Loewenstein et al. (2003)'),
('anchoring-adjustment','Insufficient Adjustment','Adjusting too little away from an initial anchor.','["Landing near a starting figure despite new data"]'::jsonb,'["Adjust more aggressively","Estimate from scratch and compare"]'::jsonb,'Epley & Gilovich (2006)'),
('bias-blind-spot','Bias Blind Spot','Seeing bias in others but not in oneself.','["Believing you are uniquely objective"]'::jsonb,'["Assume you are biased too","Use external checks"]'::jsonb,'Pronin et al. (2002)'),
('false-consensus','False-Consensus Effect','Overestimating how much others share your views.','["Assuming most people agree with you"]'::jsonb,'["Sample real opinions","Seek dissent explicitly"]'::jsonb,'Ross et al. (1977)'),
('illusion-of-transparency','Illusion of Transparency','Overestimating how visible your internal state is to others.','["Assuming your nervousness is obvious"]'::jsonb,'["Ask for feedback","Assume less is shown"]'::jsonb,'Gilovich et al. (1998)'),
('hard-easy','Hard–Easy Effect','Overconfidence on hard tasks, underconfidence on easy ones.','["Being surest on the trickiest questions"]'::jsonb,'["Calibrate by difficulty","Track hit rates per tier"]'::jsonb,'Lichtenstein & Fischhoff (1977)'),
('less-is-better','Less-Is-Better Effect','Preferring a lesser option when items are judged separately.','["A small full cup beating a larger partly-full one"]'::jsonb,'["Compare options jointly","Use absolute measures"]'::jsonb,'Hsee (1998)'),
('distinction-bias','Distinction Bias','Overvaluing differences when options are viewed side by side.','["Fixating on a spec gap that will not matter in use"]'::jsonb,'["Imagine experiencing each alone","Weight by real impact"]'::jsonb,'Hsee & Zhang (2004)'),
('rosy-retrospection','Rosy Retrospection','Remembering the past more positively than it was.','["“The good old days” that were not"]'::jsonb,'["Consult contemporaneous records","Note memory’s positivity drift"]'::jsonb,'Mitchell et al. (1997)'),
('pessimism','Pessimism Bias','Overestimating the likelihood of negative outcomes.','["Assuming the worst despite favorable odds"]'::jsonb,'["Use base rates","Separate fear from probability"]'::jsonb,'Behavioral literature'),
('normalcy','Normalcy Bias','Underestimating the likelihood and impact of a disaster.','["Ignoring warnings because things seem normal"]'::jsonb,'["Rehearse contingencies","Take early signals seriously"]'::jsonb,'Disaster psychology literature'),
('outcome','Outcome Bias','Judging a decision by its result rather than its quality.','["Praising a lucky reckless bet"]'::jsonb,'["Evaluate the process","Separate skill from luck"]'::jsonb,'Baron & Hershey (1988)'),
('choice-supportive','Choice-Supportive Bias','Remembering chosen options as better than they were.','["Recalling a past purchase too fondly"]'::jsonb,'["Keep pre-choice notes","Compare honestly"]'::jsonb,'Mather et al. (2000)'),
('information-bias','Information Bias','Seeking information that cannot change a decision.','["Ordering tests whose results will not alter the plan"]'::jsonb,'["Ask if the data changes action","Value of information first"]'::jsonb,'Baron et al. (1988)'),
('unit-bias','Unit Bias','Treating a provided unit as the appropriate amount.','["Finishing a whole serving because it was served"]'::jsonb,'["Pre-portion deliberately","Question the default unit"]'::jsonb,'Geier et al. (2006)'),
('default-effect','Default Effect','Sticking with a pre-set option.','["Keeping the default contribution rate"]'::jsonb,'["Actively choose","Re-derive the best option"]'::jsonb,'Johnson & Goldstein (2003)'),
('gaze-heuristic','Salience Bias','Focusing on prominent items and ignoring the rest.','["Reacting to a headline number, missing the footnote"]'::jsonb,'["Scan the full data","Down-weight what merely stands out"]'::jsonb,'Attention literature'),
('confabulation','Narrative Bias','Constructing a tidy story from noisy events.','["Explaining random moves with a clean cause"]'::jsonb,'["Prefer probabilistic accounts","Resist over-tidy stories"]'::jsonb,'Taleb (2007)')
